import * as THREE from 'three';
import { Sky } from 'three/addons/objects/Sky.js';
import { liveTokenReader, type ElementCategoryToken, type ViewportPaintBundle } from './materials';

export const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';

export function categoryColorOr(
  bundle: ViewportPaintBundle | null,
  cat: ElementCategoryToken,
): string {
  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
}

export function readToken(name: string, fallback: string): string {
  const v = liveTokenReader().read(name);
  return v && v.trim().length > 0 ? v : fallback;
}

/** Resolve a CSS color token to an rgb() string that Three.js can parse.
 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
 * Three.js does not support — routing through a DOM element forces the
 * browser to resolve it to "rgb(r, g, b)". */
export function readColorToken(name: string, fallback: string): string {
  if (typeof document === 'undefined') return fallback;
  try {
    const el = document.createElement('div');
    el.style.display = 'none';
    el.style.color = `var(${name}, ${fallback})`;
    document.body.appendChild(el);
    const resolved = getComputedStyle(el).color;
    document.body.removeChild(el);
    return resolved || fallback;
  } catch {
    return fallback;
  }
}

export function sunPositionFromAzEl(
  azimuthDeg: number,
  elevationDeg: number,
  radiusM = 80,
): THREE.Vector3 {
  const az = THREE.MathUtils.degToRad(azimuthDeg);
  const el = THREE.MathUtils.degToRad(elevationDeg);
  return new THREE.Vector3(
    radiusM * Math.cos(el) * Math.sin(az),
    radiusM * Math.sin(el),
    radiusM * Math.cos(el) * Math.cos(az),
  );
}

export function buildSkyEnvMap(
  renderer: THREE.WebGLRenderer,
  azimuthDeg: number,
  elevationDeg: number,
): THREE.Texture {
  const sky = new Sky();
  sky.scale.setScalar(450000);
  const u = sky.material.uniforms;
  u['turbidity'].value = 3;
  u['rayleigh'].value = 0.5;
  u['mieCoefficient'].value = 0.005;
  u['mieDirectionalG'].value = 0.8;
  const phi = THREE.MathUtils.degToRad(90 - elevationDeg);
  const theta = THREE.MathUtils.degToRad(azimuthDeg);
  u['sunPosition'].value.setFromSphericalCoords(1, phi, theta);
  const pmrem = new THREE.PMREMGenerator(renderer);
  pmrem.compileEquirectangularShader();
  const tempScene = new THREE.Scene();
  tempScene.add(sky);
  const envTexture = pmrem.fromScene(tempScene).texture;
  pmrem.dispose();
  (sky.material as THREE.ShaderMaterial).dispose();
  sky.geometry.dispose();
  return envTexture;
}

export function addEdges(mesh: THREE.Mesh, thresholdAngleDeg = 15): THREE.LineSegments {
  const color = readToken('--color-foreground', '#1a1a1a');
  const edges = new THREE.EdgesGeometry(mesh.geometry, thresholdAngleDeg);
  const mat = new THREE.LineBasicMaterial({ color, linewidth: 1 });
  const lines = new THREE.LineSegments(edges, mat);
  lines.renderOrder = 1;
  lines.castShadow = false;
  lines.receiveShadow = false;
  mesh.add(lines);
  return lines;
}

def _dump_elements(elements: dict[str, Element]) -> dict[str, Any]:
    return {k: v.model_dump(by_alias=True) for k, v in elements.items()}


def clone_document(doc: Document) -> Document:
    payload = {"revision": doc.revision, "elements": _dump_elements(doc.elements)}
    return Document.model_validate(payload)


def ensure_internal_origin(doc: Document) -> Document:
    """KRN-06: ensure the singleton `internal_origin` element exists.

    Mutates `doc.elements` in place when missing and returns the same Document.
    Idempotent. Called on model creation and on first snapshot read so legacy
    models acquire one without requiring a migration.
    """
    if any(isinstance(e, InternalOriginElem) for e in doc.elements.values()):
        return doc
    doc.elements[INTERNAL_ORIGIN_ID] = InternalOriginElem(
        kind="internal_origin", id=INTERNAL_ORIGIN_ID
    )
    return doc


def _wall_elevation_mm(els: dict[str, Element], level_id: str) -> float:
    lv = els.get(level_id)
    if isinstance(lv, LevelElem):
        return float(lv.elevation_mm)
    return 0.0


def _resolve_wall_height_mm(cmd: CreateWallCmd, els: dict[str, Element]) -> float:
    if cmd.base_constraint_level_id and cmd.top_constraint_level_id:
        b = _wall_elevation_mm(els, cmd.base_constraint_level_id) + cmd.base_constraint_offset_mm
        t = _wall_elevation_mm(els, cmd.top_constraint_level_id) + cmd.top_constraint_offset_mm
        return max(100.0, t - b)
    return cmd.height_mm


def _basis_line(val: str) -> WallBasisLine:
    choices: tuple[WallBasisLine, ...] = ("center", "face_interior", "face_exterior")
    lowered = val.strip().lower()
    if lowered in choices:
        return cast(WallBasisLine, lowered)
    return "center"


def _recompute_constrained_wall_heights(els: dict[str, Element]) -> None:
    for wid, el in list(els.items()):
        if not isinstance(el, WallElem):
            continue
        if not (el.base_constraint_level_id and el.top_constraint_level_id):
            continue
        b = _wall_elevation_mm(els, el.base_constraint_level_id) + el.base_constraint_offset_mm
        t = _wall_elevation_mm(els, el.top_constraint_level_id) + el.top_constraint_offset_mm
        nh = max(100.0, t - b)
        if abs(nh - el.height_mm) > 1e-3:
            els[wid] = el.model_copy(update={"height_mm": nh})


def _wall_thickness_from_type(
    els: dict[str, Element], wall_type_id: str | None, fallback: float
) -> float:
    if not wall_type_id:
        return fallback
    wt = els.get(wall_type_id)
    if not isinstance(wt, WallTypeElem) or not wt.layers:
        return fallback
    return float(sum(lyr.thickness_mm for lyr in wt.layers)) or fallback


def _floor_dims_from_type(
    els: dict[str, Element], floor_type_id: str | None
) -> tuple[float, float, float] | None:
    if not floor_type_id:
        return None
    ft = els.get(floor_type_id)
    if not isinstance(ft, FloorTypeElem) or not ft.layers:
        return None

